exercises.correction:
PASSED=0; FAILED=0

assert_eq() {
    if [ "$1" = "$2" ]; then
        echo "[PASS] $1 == $2"; ((PASSED++))
    else
        echo "[FAIL] $1 != $2 (attendu égal)"; ((FAILED++))
    fi
}

assert_ne() {
    if [ "$1" != "$2" ]; then
        echo "[PASS] $1 != $2"; ((PASSED++))
    else
        echo "[FAIL] $1 == $2 (attendu différent)"; ((FAILED++))
    fi
}

assert_eq "hello" "hello"
assert_ne "foo" "bar"
assert_eq "foo" "bar"

echo "Résultat : $PASSED passés, $FAILED échoués"
